const CareerHub: React.FC<CareerHubProps> = ({ gameData, setGameData, onResetGame, theme, setTheme, saveGame, loadGame, showFeedback }) => {
    const [screen, setScreen] = useState<CareerScreen>('DASHBOARD');
    const [selectedPlayer, setSelectedPlayer] = useState<Player | null>(null);
    const [playerProfileFormat, setPlayerProfileFormat] = useState<Format>(gameData.currentFormat);
    const [selectedMatchResult, setSelectedMatchResult] = useState<MatchResult | null>(null);
    const [forwardSimResults, setForwardSimResults] = useState<MatchResult[]>([]);

    const { runSimulationForCurrentFormat, updateStatsFromMatch } = useSimulation(gameData, setGameData);

    useEffect(() => {
        if (gameData && (!gameData.sponsorships || !gameData.popularity || !gameData.news)) {
             setGameData(prev => {
                 if (!prev) return null;
                 return {
                     ...prev,
                     popularity: prev.popularity ?? 50,
                     sponsorships: prev.sponsorships ?? INITIAL_SPONSORSHIPS,
                     news: prev.news ?? INITIAL_NEWS
                 };
             });
        }
    }, [gameData, setGameData]);

    const userTeam = useMemo(() => {
        const team = gameData.teams.find(t => t.id === gameData.userTeamId);
        return team || gameData.teams[0];
    }, [gameData]);

    useEffect(() => {
        const schedule = gameData.schedule[gameData.currentFormat];
        const currentMatchIndex = gameData.currentMatchIndex[gameData.currentFormat];

        if (currentMatchIndex >= schedule.length) {
            const awardExists = gameData.awardsHistory.some(a => a.season === gameData.currentSeason && a.format === gameData.currentFormat);

            if (!awardExists) {
                const formatStats = new Map();
                gameData.teams.forEach(team => team.squad.forEach(player => {
                    const p = getPlayerById(player.id, gameData.allPlayers);
                    if (p) {
                       formatStats.set(p.id, { runs: p.stats[gameData.currentFormat].runs, wickets: p.stats[gameData.currentFormat].wickets, teamName: team.name, playerName: p.name })
                    }
                }));

                const sortedBatters = [...formatStats.entries()].sort((a, b) => b[1].runs - a[1].runs);
                const sortedBowlers = [...formatStats.entries()].sort((a, b) => b[1].wickets - a[1].wickets);

                const finalMatchNumber = schedule[schedule.length-1].matchNumber;
                const lastMatchResult = gameData.matchResults[gameData.currentFormat].find(r => r.matchNumber === finalMatchNumber);
                const winnerTeam = gameData.teams.find(t => t.id === lastMatchResult?.winnerId);

                const newAward = { 
                    season: gameData.currentSeason, 
                    format: gameData.currentFormat, 
                    winnerTeamId: winnerTeam?.id || '', 
                    winnerTeamName: winnerTeam?.name || 'N/A', 
                    bestBatter: { playerId: sortedBatters[0]?.[0] || '', playerName: sortedBatters[0]?.[1].playerName || 'N/A', teamName: sortedBatters[0]?.[1].teamName || 'N/A', runs: sortedBatters[0]?.[1].runs || 0 }, 
                    bestBowler: { playerId: sortedBowlers[0]?.[0] || '', playerName: sortedBowlers[0]?.[1].playerName || 'N/A', teamName: sortedBowlers[0]?.[1].teamName || 'N/A', wickets: sortedBowlers[0]?.[1].wickets || 0 } 
                };

                setGameData(prev => prev ? { ...prev, awardsHistory: [...prev.awardsHistory, newAward] } : null);
                setScreen('END_OF_FORMAT');
            }
        }
    }, [gameData.currentMatchIndex, gameData.currentFormat, gameData.currentSeason, gameData.awardsHistory, gameData.teams, gameData.allPlayers, gameData.matchResults, gameData.schedule, setGameData]);

    const handleUpdatePlayer = (updatedPlayer: Player) => {
        setGameData(prevData => {
            if (!prevData) return null;
            const newAllPlayers = prevData.allPlayers.map(p => p.id === updatedPlayer.id ? updatedPlayer : p);
            const newTeams = prevData.teams.map(team => ({
                ...team,
                squad: team.squad.map(squadPlayer => newAllPlayers.find(p => p.id === squadPlayer.id) || squadPlayer)
            }));
            return { ...prevData, allPlayers: newAllPlayers, teams: newTeams };
        });
    };

    const handleCreatePlayer = (newPlayer: Player) => {
        setGameData(prevData => {
            if (!prevData) return null;
            return { ...prevData, allPlayers: [...prevData.allPlayers, newPlayer] };
        });
    };

    const handleUpdateGround = (code: string, newPitch: string) => setGameData(prev => prev ? { ...prev, grounds: prev.grounds.map(g => g.code === code ? { ...g, pitch: newPitch } : g) } : null);

    const handleUpdateScoreLimits = (groundCode: string, format: Format, field: any, value: any, inning: number) => {
        setGameData(prev => {
            if (!prev) return null;
            const numValue = parseInt(value, 10);
            const newLimits: any = JSON.parse(JSON.stringify(prev.scoreLimits || {}));
            if (!newLimits[groundCode]) newLimits[groundCode] = {};
            if (!newLimits[groundCode][format]) newLimits[groundCode][format] = {};
            if (!newLimits[groundCode][format][inning]) newLimits[groundCode][format][inning] = {};

            if (value === '' || isNaN(numValue) || numValue <= 0) {
                delete newLimits[groundCode][format][inning][field];
            } else {
                newLimits[groundCode][format][inning][field] = numValue;
            }

            return { ...prev, scoreLimits: newLimits };
        });
    };

    const handleUpdateCaptain = (teamId: string, format: Format, playerId: string) => {
        setGameData(prevData => {
            if (!prevData) return null;
            return {
                ...prevData,
                teams: prevData.teams.map(t => {
                    if (t.id === teamId) {
                        return { ...t, captains: { ...t.captains, [format]: playerId } };
                    }
                    return t;
                })
            };
        });
        showFeedback("Captain updated!");
    };

    const handleUpdatePlayingXI = (teamId: string, format: Format, newXI: string[]) => {
        setGameData(prevData => {
            if (!prevData) return null;
            const teamXIs = prevData.playingXIs[teamId] || {};
            return {
                ...prevData,
                playingXIs: {
                    ...prevData.playingXIs,
                    [teamId]: {
                        ...teamXIs,
                        [format]: newXI
                    }
                }
            };
        });
    };

    const simulateBackgroundMatches = (currentData: GameData): GameData => {
        let updatedData = JSON.parse(JSON.stringify(currentData)) as GameData;
        Object.values(Format).forEach(f => {
            if (f === updatedData.currentFormat) return; // Already handled by main loop

            const schedule = updatedData.schedule[f];
            let mIdx = updatedData.currentMatchIndex[f];

            // Sim up to 2 matches per format to keep up
            for (let i = 0; i < 2; i++) {
                if (mIdx < schedule.length) {
                    let match = JSON.parse(JSON.stringify(schedule[mIdx]));

                    // Resolve placeholder for knockouts
                    if (match.group !== 'Round-Robin') {
                        const standings = updatedData.standings[f];
                        const getTeamName = (pos: number) => standings[pos - 1]?.teamName;
                        const resolvePlaceholder = (placeholder: string) => {
                            if (['1st', '2nd', '3rd', '4th'].includes(placeholder)) return getTeamName(parseInt(placeholder[0]));
                            if (placeholder.startsWith('SF')) {
                                const sfRes = updatedData.matchResults[f].find(r => r.matchNumber === placeholder.split(' ')[0]);
                                return updatedData.teams.find(t => t.id === sfRes?.winnerId)?.name || 'TBD';
                            }
                            return placeholder;
                        };
                        match.teamA = resolvePlaceholder(match.teamA) || 'TBD';
                        match.teamB = resolvePlaceholder(match.teamB) || 'TBD';
                        if (match.teamA === 'TBD' || match.teamB === 'TBD') break;
                    }

                    // Background sim
                    const result = runSimulationForCurrentFormat(match, updatedData);
                    updatedData = updateStatsFromMatch(result, f, updatedData);
                    updatedData.currentMatchIndex[f]++;
                    mIdx++;
                }
            }
        });
        return updatedData;
    };

    const handleForwardDay = () => {
        if (!userTeam) return;
        let currentData = { ...gameData };
        let matchIndex = currentData.currentMatchIndex[currentData.currentFormat];
        let schedule = currentData.schedule[currentData.currentFormat];
        const results: MatchResult[] = [];
        // Fix: Explicitly type newNewsItems as NewsArticle[] to prevent 'any[]' widening issues
        const newNewsItems: NewsArticle[] = [];

        // Simulate other formats in background
        currentData = simulateBackgroundMatches(currentData);

        for(let i=0; i<5; i++) {
            if (matchIndex + i < schedule.length) {
                const m = schedule[matchIndex+i];
                if (m.teamA === userTeam.name || m.teamB === userTeam.name) {
                    const preNews = generatePreMatchNews(m, currentData);
                    newNewsItems.push(preNews);
                    break;
                }
            }
        }

        let simulatedCount = 0;
        const maxSimulations = 5;

        while (matchIndex < schedule.length && simulatedCount < maxSimulations) {
            let matchToSim = JSON.parse(JSON.stringify(schedule[matchIndex]));

            if (matchToSim.group !== 'Round-Robin') {
                const standings = currentData.standings[currentData.currentFormat];
                const getTeamName = (pos: number) => standings[pos - 1]?.teamName;
                const resolvePlaceholder = (placeholder: string) => {
                    if (['1st', '2nd', '3rd', '4th'].includes(placeholder)) {
                        const pos = parseInt(placeholder[0]);
                        return getTeamName(pos);
                    }
                    if (placeholder.startsWith('SF')) {
                        const sfMatchNumber = placeholder.split(' ')[0];
                        const sfResult = currentData.matchResults[currentData.currentFormat].find(r => r.matchNumber === sfMatchNumber);
                        const winner = currentData.teams.find(t => t.id === sfResult?.winnerId);
                        return winner?.name || null;
                    }
                    return placeholder;
                };
                matchToSim.teamA = resolvePlaceholder(matchToSim.teamA) || 'TBD';
                matchToSim.teamB = resolvePlaceholder(matchToSim.teamB) || 'TBD';

                if (matchToSim.teamA === 'TBD' || matchToSim.teamB === 'TBD') break; 
            }

            const isUserTeamMatch = matchToSim.teamA === userTeam.name || matchToSim.teamB === userTeam.name;
            if (isUserTeamMatch) break;

            const result = runSimulationForCurrentFormat(matchToSim, currentData);
            currentData = updateStatsFromMatch(result, currentData.currentFormat, currentData);
            currentData.currentMatchIndex[currentData.currentFormat]++; 
            results.push(result);
            simulatedCount++;

            if (matchToSim.group !== 'Round-Robin' || Math.random() < 0.3) {
                const sponsorship = currentData.sponsorships?.[currentData.currentFormat] || INITIAL_SPONSORSHIPS[currentData.currentFormat];
                newNewsItems.push(generateMatchNews(result, currentData.currentFormat, sponsorship));
            }

            matchIndex++;
        }

        if (newNewsItems.length > 0) currentData.news = [...newNewsItems, ...currentData.news].slice(0, 50);

        if (results.length > 0) {
            setForwardSimResults(results);
            setGameData(currentData); 
            setScreen('FORWARD_RESULTS');
        } else {
             if (matchIndex < schedule.length) {
                 if (newNewsItems.length > 0) {
                     setGameData(prev => prev ? { ...prev, news: [...newNewsItems, ...prev.news] } : null);
                 }
                 showFeedback("Your match is next or waiting for opponent!", "success");
             }
        }
    };

    const handlePlayMatch = () => {
        if (!userTeam) return;

        const schedule = gameData.schedule[gameData.currentFormat];
        const currentMatchIndex = gameData.currentMatchIndex[gameData.currentFormat];
        if (currentMatchIndex >= schedule.length) return;

        let matchToSim = JSON.parse(JSON.stringify(schedule[currentMatchIndex]));

        if (matchToSim.group !== 'Round-Robin') {
             const standings = gameData.standings[gameData.currentFormat];
             const getTeamName = (pos: number) => standings[pos - 1]?.teamName;
             const resolvePlaceholder = (placeholder: string) => {
                if (['1st', '2nd', '3rd', '4th'].includes(placeholder)) return getTeamName(parseInt(placeholder[0]));
                if (placeholder.startsWith('SF')) {
                    const sfMatchNumber = placeholder.split(' ')[0];
                    const sfResult = gameData.matchResults[gameData.currentFormat].find(r => r.matchNumber === sfMatchNumber);
                    return gameData.teams.find(t => t.id === sfResult?.winnerId)?.name || null;
                }
                return placeholder;
            };
            matchToSim.teamA = resolvePlaceholder(matchToSim.teamA) || 'TBD';
            matchToSim.teamB = resolvePlaceholder(matchToSim.teamB) || 'TBD';
        }

        if (matchToSim.teamA === 'TBD' || matchToSim.teamB === 'TBD') {
            showFeedback("Cannot play match, opponent not yet decided.", "error");
            return;
        }

        const isInteractiveFormat = gameData.currentFormat === Format.T20 || gameData.currentFormat === Format.ODI;
        const isUserTeamMatch = matchToSim.teamA === userTeam.name || matchToSim.teamB === userTeam.name;

        if (isUserTeamMatch && isInteractiveFormat) {
             setScreen('LIVE_MATCH');
        } else {
             // AUTO-SIMULATE
             const result = runSimulationForCurrentFormat(matchToSim, gameData);
             const updatedData = updateStatsFromMatch(result, gameData.currentFormat, gameData);
             updatedData.currentMatchIndex[gameData.currentFormat]++;
             const sponsorship = updatedData.sponsorships?.[updatedData.currentFormat] || INITIAL_SPONSORSHIPS[updatedData.currentFormat];
             const newsItem = generateMatchNews(result, updatedData.currentFormat, sponsorship);
             updatedData.news = [newsItem, ...updatedData.news].slice(0, 50);
             setGameData(updatedData);
             setSelectedMatchResult(result);
             setScreen('MATCH_RESULT');
        }
    };

    const handleLiveMatchComplete = (result: MatchResult) => {
        const updatedData = updateStatsFromMatch(result, gameData.currentFormat, gameData);
        updatedData.currentMatchIndex[gameData.currentFormat]++;
        updatedData.activeMatch = null; 
        const sponsorship = updatedData.sponsorships?.[updatedData.currentFormat] || INITIAL_SPONSORSHIPS[updatedData.currentFormat];
        const newsItem = generateMatchNews(result, updatedData.currentFormat, sponsorship);
        updatedData.news = [newsItem, ...updatedData.news].slice(0, 50);
        setGameData(updatedData);
        setSelectedMatchResult(result);
        setScreen('MATCH_RESULT');
    };

    const handleLiveMatchExit = (stateToSave?: LiveMatchState) => {
        if (stateToSave) {
            setGameData(prev => prev ? { ...prev, activeMatch: stateToSave } : null);
            showFeedback("Match progress saved.", "success");
        } else setGameData(prev => prev ? { ...prev, activeMatch: null } : null);
        setScreen('DASHBOARD');
    }

    const handleFormatChange = useCallback((newFormat: Format) => {
        setGameData(prev => prev ? ({ ...prev, currentFormat: newFormat }) : null);
        setScreen('DASHBOARD');
    }, [setGameData]);

    const handleEndOfSeason = useCallback((retainedPlayers: Player[]) => {
        // Fix: Explicitly type prevData to avoid widening issues in the return object
        setGameData((prevData: GameData | null) => {
            if (!prevData) return null;

            // Costs PKr 1 Cr premium per retained player
            const retentionCost = retainedPlayers.length * 1.0; 

            const mainLeagueTeams = prevData.teams.filter(t => !prevData.allTeamsData.find(td => td.id === t.id)?.isDevelopmentTeam);
            const mainTeamStats = mainLeagueTeams.map(team => {
                const totalPoints = (prevData.standings[Format.T20].find(s => s.teamId === team.id)?.points || 0) +
                                   (prevData.standings[Format.ODI].find(s => s.teamId === team.id)?.points || 0) +
                                   (prevData.standings[Format.FIRST_CLASS].find(s => s.teamId === team.id)?.points || 0);
                return { team, totalPoints };
            });
            const relegatedTeams = mainTeamStats.sort((a, b) => a.totalPoints - b.totalPoints).slice(0, 2).map(i => i.team);

            const devTeams = prevData.teams.filter(t => prevData.allTeamsData.find(td => td.id === t.id)?.isDevelopmentTeam);
            const getDevPoints = (id: string) => (prevData.standings[Format.DEVELOPMENT_T20].find(s => s.teamId === id)?.points || 0) + (prevData.standings[Format.DEVELOPMENT_ODI].find(s => s.teamId === id)?.points || 0);
            const promotedTeams = devTeams.sort((a,b) => getDevPoints(b.id) - getDevPoints(a.id)).slice(0, 2);

            const newAllTeamsData = prevData.allTeamsData.map(t => {
                if (relegatedTeams.find(rt => rt.id === t.id)) return { ...t, isDevelopmentTeam: true };
                if (promotedTeams.find(pt => pt.id === t.id)) return { ...t, isDevelopmentTeam: false };
                return t;
            });

            const newTeams = prevData.teams.map(t => {
                if (t.id === prevData.userTeamId) return { ...t, squad: retainedPlayers, purse: 50.0 - retentionCost };
                const aiRetainCount = 2 + Math.floor(Math.random() * 3);
                const aiRetained = t.squad.sort((a,b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill)).slice(0, aiRetainCount);
                const aiCost = aiRetained.length * 1.0;
                return { ...t, squad: aiRetained, purse: 50.0 - aiCost };
            });

            const finalMainTeams = newTeams.filter(t => !newAllTeamsData.find(td => td.id === t.id)?.isDevelopmentTeam);
            const finalDevTeams = newTeams.filter(t => newAllTeamsData.find(td => td.id === t.id)?.isDevelopmentTeam);
            const initialStandings = (teams: Team[]) => teams.map(team => ({ teamId: team.id, teamName: team.name, played: 0, won: 0, lost: 0, drawn: 0, points: 0, netRunRate: 0, runsFor: 0, runsAgainst: 0 }));

            // Fix: Cast news item as NewsArticle and use 'as const' to prevent literal type widening
            const seasonNews: NewsArticle = { 
                id: `s${prevData.currentSeason}-end`, 
                headline: `Season ${prevData.currentSeason+1} Draft Room Open!`, 
                date: new Date().toLocaleDateString(), 
                excerpt: "Teams reveal retained players.", 
                content: "Windows for retention have closed. Teams are heading to the auction floor with updated budgets.", 
                type: 'league' as const
            };

            return {
                ...prevData,
                allTeamsData: newAllTeamsData,
                currentSeason: prevData.currentSeason + 1,
                currentFormat: Format.T20,
                /* Fix: Explicitly cast initial value of reduce to Record<Format, number> to match GameData type */
                currentMatchIndex: Object.values(Format).reduce((acc, f) => ({ ...acc, [f]: 0 }), {} as Record<Format, number>),
                /* Fix: Explicitly cast initial value of reduce to Record<Format, MatchResult[]> to match GameData type */
                matchResults: Object.values(Format).reduce((acc, f) => ({ ...acc, [f]: [] }), {} as Record<Format, MatchResult[]>),
                standings: { [Format.T20]: initialStandings(finalMainTeams), [Format.ODI]: initialStandings(finalMainTeams), [Format.FIRST_CLASS]: initialStandings(finalMainTeams), [Format.DEVELOPMENT_T20]: initialStandings(finalDevTeams), [Format.DEVELOPMENT_ODI]: initialStandings(finalDevTeams), [Format.DEVELOPMENT_FIRST_CLASS]: initialStandings(finalDevTeams), [Format.RISE_T20]: initialStandings(finalDevTeams), [Format.RISE_ODI]: initialStandings(finalDevTeams), [Format.RISE_FIRST_CLASS]: initialStandings(finalDevTeams) },
                schedule: { 
                    [Format.T20]: generateLeagueSchedule(finalMainTeams, Format.T20, prevData.settings.isDoubleRoundRobin), 
                    [Format.ODI]: generateLeagueSchedule(finalMainTeams, Format.ODI, prevData.settings.isDoubleRoundRobin), 
                    [Format.FIRST_CLASS]: generateLeagueSchedule(finalMainTeams, Format.FIRST_CLASS, prevData.settings.isDoubleRoundRobin), 
                    [Format.DEVELOPMENT_T20]: generateLeagueSchedule(finalDevTeams, Format.DEVELOPMENT_T20, prevData.settings.isDoubleRoundRobin), 
                    [Format.DEVELOPMENT_ODI]: generateLeagueSchedule(finalDevTeams, Format.DEVELOPMENT_ODI, prevData.settings.isDoubleRoundRobin), 
                    [Format.DEVELOPMENT_FIRST_CLASS]: generateLeagueSchedule(finalDevTeams, Format.DEVELOPMENT_FIRST_CLASS, prevData.settings.isDoubleRoundRobin), 
                    [Format.RISE_T20]: generateLeagueSchedule(finalDevTeams, Format.RISE_T20, prevData.settings.isDoubleRoundRobin), 
                    [Format.RISE_ODI]: generateLeagueSchedule(finalDevTeams, Format.RISE_ODI, prevData.settings.isDoubleRoundRobin), 
                    [Format.RISE_FIRST_CLASS]: generateLeagueSchedule(finalDevTeams, Format.RISE_FIRST_CLASS, prevData.settings.isDoubleRoundRobin) 
                },
                teams: newTeams,
                // Fix: Prepend explicitly typed seasonNews article
                news: [seasonNews, ...prevData.news].slice(0, 50)
            };
        });
        setScreen('AUCTION_ROOM');
    }, [setGameData]);

    const renderScreen = () => {
        const commonProps = { gameData, userTeam, setGameData, setScreen, showFeedback };
        switch(screen) {
            case 'DASHBOARD': return <Dashboard {...commonProps} handlePlayMatch={handlePlayMatch} handleForwardDay={handleForwardDay} />;
            case 'LEAGUES': return <Standings gameData={gameData} />; 
            case 'SCHEDULE': return <Schedule gameData={gameData} userTeam={userTeam} viewMatchResult={result => { setSelectedMatchResult(result); setScreen('MATCH_RESULT'); }} />;
            case 'LINEUPS': return <Lineups {...commonProps} handleUpdatePlayingXI={handleUpdatePlayingXI} handleUpdateCaptain={handleUpdateCaptain} />;
            case 'EDITOR': return <Editor {...commonProps} handleUpdatePlayer={handleUpdatePlayer} handleCreatePlayer={handleCreatePlayer} handleUpdateGround={handleUpdateGround} handleUpdateScoreLimits={handleUpdateScoreLimits} />;
            case 'NEWS': return <News news={gameData.news} />;
            case 'STATS': return <Stats gameData={gameData} viewPlayerProfile={(p, f) => { setSelectedPlayer(p); setPlayerProfileFormat(f); setScreen('PLAYER_PROFILE'); }} />;
            case 'SETTINGS': return <Settings onResetGame={onResetGame} theme={theme} setTheme={setTheme} saveGame={saveGame} loadGame={loadGame} />;
            case 'PLAYER_PROFILE': return <PlayerProfile player={selectedPlayer} onBack={() => setScreen('STATS')} initialFormat={playerProfileFormat} />;
            case 'MATCH_RESULT': return <MatchResultScreen result={selectedMatchResult} onBack={() => setScreen('DASHBOARD')} userTeamId={gameData.userTeamId} />;
            case 'FORWARD_RESULTS': return <ForwardResultsScreen results={forwardSimResults} onBack={() => setScreen('DASHBOARD')} userTeamId={gameData.userTeamId} />;
            case 'AWARDS_RECORDS': return <AwardsAndRecordsScreen gameData={gameData} />;
            case 'END_OF_FORMAT': return <EndOfFormatScreen gameData={gameData} handleFormatChange={handleFormatChange} handleEndSeason={handleEndOfSeason} />;
            case 'TRANSFERS': return <Transfers {...commonProps} />;
            case 'COMPARISON': return <ComparisonScreen gameData={gameData} />;
            case 'ASSISTANT': return <Assistant gameData={gameData} />;
            case 'SPONSOR_ROOM': return <SponsorRoom gameData={gameData} setGameData={setGameData} />;
            case 'AUCTION_ROOM': return <AuctionRoom gameData={gameData} onAuctionComplete={(teams) => { 
                setGameData(prev => prev ? { ...prev, teams } : null);
                setScreen('DASHBOARD');
            }} />;
            case 'LIVE_MATCH': {
                const schedule = gameData.schedule[gameData.currentFormat];
                const currentMatchIndex = gameData.currentMatchIndex[gameData.currentFormat];
                const match = schedule[currentMatchIndex];
                let resolvedMatch = match ? JSON.parse(JSON.stringify(match)) : null;
                if (resolvedMatch) {
                    const resolvePlaceholder = (placeholder: string) => {
                        if (['1st', '2nd', '3rd', '4th'].includes(placeholder)) {
                            const pos = parseInt(placeholder[0]);
                            return gameData.standings[gameData.currentFormat][pos-1]?.teamName || 'TBD';
                        }
                        if (placeholder.startsWith('SF')) {
                            const sfResult = gameData.matchResults[gameData.currentFormat].find(r => r.matchNumber === placeholder.split(' ')[0]);
                            return gameData.teams.find(t => t.id === sfResult?.winnerId)?.name || 'TBD';
                        }
                        return placeholder;
                    };
                    resolvedMatch.teamA = resolvePlaceholder(resolvedMatch.teamA);
                    resolvedMatch.teamB = resolvePlaceholder(resolvedMatch.teamB);
                }
                return resolvedMatch ? (
                    <LiveMatchScreen match={resolvedMatch} gameData={gameData} onMatchComplete={handleLiveMatchComplete} onExit={handleLiveMatchExit} /> 
                ) : <div className="p-4 text-center"><p>Tournament finished.</p><button onClick={() => setScreen('DASHBOARD')} className="mt-4 bg-teal-500 text-white px-4 py-2 rounded">Back</button></div>;
            }
            default: return <div>Coming Soon</div>
        }
    }

    return (
        <div className="flex flex-col h-full">
            <main className="flex-grow overflow-y-auto">{renderScreen()}</main>
            <BottomNavBar activeScreen={screen} setScreen={setScreen} />
        </div>
    );
};

export default CareerHub;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Player, Team, GameData, PlayerRole, Format } from '../types';
import { getRoleColor, getRoleFullName, aggregateStats } from '../utils';
import { Icons } from './Icons';

interface AuctionRoomProps {
    gameData: GameData;
    onAuctionComplete: (updatedTeams: Team[]) => void;
}

const STARTING_PURSE = 50.0;
const MAX_FOREIGN_LIMIT = 2;

// Targeted Balanced Squad Ratios
const TARGET_OPENERS = 4;
const TARGET_BATTERS = 7; // specialists total
const TARGET_KEEPERS = 1;
const TARGET_ALL_ROUNDERS = 3;
const TARGET_SPINNERS = 3;
const TARGET_FAST = 5;

// Helper to shuffle array
const shuffle = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
};

const AuctionRoom: React.FC<AuctionRoomProps> = ({ gameData, onAuctionComplete }) => {
    const mainTeamIds = useMemo(() => 
        gameData.allTeamsData.filter(td => !td.isDevelopmentTeam).map(td => td.id), 
    [gameData.allTeamsData]);

    const [teams, setTeams] = useState<Team[]>(() => 
        gameData.teams.map(t => ({ ...t, squad: t.squad || [], purse: t.purse || STARTING_PURSE }))
    );

    const [activeOverlay, setActiveOverlay] = useState<'none' | 'franchises' | 'pool'>('none');

    // Sorted Pool: Best to Worst based on max skill
    const sortedPool = useMemo(() => {
        const retainedPlayerIds = new Set(teams.flatMap(t => t.squad.map(p => p.id)));
        return gameData.allPlayers
            .filter(pl => !retainedPlayerIds.has(pl.id))
            .sort((a, b) => {
                const skillA = Math.max(a.battingSkill, a.secondarySkill);
                const skillB = Math.max(b.battingSkill, b.secondarySkill);
                return skillB - skillA;
            });
    }, [gameData.allPlayers, teams]);

    const [currentPlayerIdx, setCurrentPlayerIdx] = useState(0);
    const [currentBid, setCurrentBid] = useState(0);
    const [highestBidderId, setHighestBidderId] = useState<string | null>(null);
    const [isAuctioning, setIsAuctioning] = useState(false);
    const [biddingLog, setBiddingLog] = useState<string[]>([]);
    const [auctionFinished, setAuctionFinished] = useState(false);

    const currentPlayer = sortedPool[currentPlayerIdx] || null;
    const userTeam = teams.find(t => t.id === gameData.userTeamId);

    // Attribute-Based Pricing Logic
    const getBasePrice = (player: Player) => {
        const attr = Math.max(player.battingSkill, player.secondarySkill);
        if (attr > 70) return 2.0;
        if (attr >= 61) return 1.0; 
        if (attr >= 51) return 0.6;
        return 0.25;
    };

    const startNextPlayer = useCallback(() => {
        if (auctionFinished) return;

        if (currentPlayerIdx >= sortedPool.length) {
            setAuctionFinished(true);
            return;
        }

        const player = sortedPool[currentPlayerIdx];
        if (!player) {
            setCurrentPlayerIdx(prev => prev + 1);
            return;
        }

        const bp = getBasePrice(player);
        setCurrentBid(bp);
        setHighestBidderId(null);
        setIsAuctioning(true);
        setBiddingLog(prev => [`Lot #${currentPlayerIdx + 1}: ${player.name} (${getRoleFullName(player.role)}) up for ${bp.toFixed(2)} Cr`, ...prev.slice(0, 5)]);
    }, [currentPlayerIdx, sortedPool, auctionFinished]);

    const handleUserBid = (multiplier: number = 1) => {
        if (!userTeam || !isAuctioning || !currentPlayer) return;

        if (currentPlayer.isForeign && userTeam.squad.filter(p => p.isForeign).length >= MAX_FOREIGN_LIMIT) {
            setBiddingLog(prev => [`Foreign limit reached!`, ...prev.slice(0, 5)]);
            return;
        }

        const increment = 0.1 * multiplier;
        const nextBid = Number((currentBid + increment).toFixed(2));
        if (userTeam.purse < nextBid) return;

        setCurrentBid(nextBid);
        setHighestBidderId(userTeam.id);
        setBiddingLog(prev => [`${userTeam.name} bids ${nextBid.toFixed(2)} Cr! (+${increment.toFixed(1)})`, ...prev.slice(0, 5)]);
    };

    const skipPlayer = () => {
        if (!currentPlayer || !isAuctioning) return;
        setIsAuctioning(false);

        const eligibleTeams = teams.filter(t => 
            mainTeamIds.includes(t.id) &&
            t.id !== gameData.userTeamId &&
            t.purse >= (getBasePrice(currentPlayer) + 0.2) &&
            t.squad.length < 22 &&
            (!currentPlayer.isForeign || t.squad.filter(p => p.isForeign).length < MAX_FOREIGN_LIMIT)
        );

        if (eligibleTeams.length > 0) {
            const winner = eligibleTeams[Math.floor(Math.random() * eligibleTeams.length)];
            const finalPrice = Number((getBasePrice(currentPlayer) + (Math.random() * 0.4)).toFixed(2));
            setTeams(prev => prev.map(t => {
                if (t.id === winner.id) {
                    return { ...t, purse: Number((t.purse - finalPrice).toFixed(2)), squad: [...t.squad, currentPlayer] };
                }
                return t;
            }));
            setBiddingLog(prev => [`Auto-Sold: ${currentPlayer.name} to ${winner.name} (${finalPrice.toFixed(2)} Cr)`, ...prev]);
        } else {
            setBiddingLog(prev => [`Player Unsold: ${currentPlayer.name}`, ...prev]);
        }

        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 200);
    };

    const autoAuctionRemaining = () => {
        setIsAuctioning(false);
        setAuctionFinished(true);
        setBiddingLog(prev => [`Finalizing balanced rosters...`, ...prev]);
    };

    useEffect(() => {
        if (!isAuctioning || !currentPlayer || auctionFinished) return;

        const timer = setTimeout(() => {
            const eligibleTeams = teams.filter(t => 
                mainTeamIds.includes(t.id) &&
                t.id !== highestBidderId && 
                t.purse >= (currentBid + 0.1) &&
                t.squad.length < 22 &&
                (!currentPlayer.isForeign || t.squad.filter(p => p.isForeign).length < MAX_FOREIGN_LIMIT)
            );

            if (eligibleTeams.length > 0) {
                const rating = Math.max(currentPlayer.battingSkill, currentPlayer.secondarySkill);

                const biddingTeam = eligibleTeams.find(t => {
                    if (t.id === gameData.userTeamId) return false;
                    // Add Random Jitter to AI valuation so teams bid differently every time
                    const jitter = 0.75 + (Math.random() * 0.5); 
                    const valuation = (rating / 80) * 12.0 * jitter; 
                    return (currentBid + 0.1) <= valuation;
                });

                if (biddingTeam) {
                    const nextBid = Number((currentBid + 0.1).toFixed(2));
                    setCurrentBid(nextBid);
                    setHighestBidderId(biddingTeam.id);
                    setBiddingLog(prev => [`${biddingTeam.name} bids ${nextBid.toFixed(2)} Cr!`, ...prev.slice(0, 5)]);
                } else if (highestBidderId) {
                    sellPlayer();
                } else {
                    unsoldPlayer();
                }
            } else if (highestBidderId) {
                sellPlayer();
            } else {
                unsoldPlayer();
            }
        }, 600 + Math.random() * 400); // Random delay to feel more natural

        return () => clearTimeout(timer);
    }, [isAuctioning, currentBid, highestBidderId, currentPlayer, gameData.userTeamId, mainTeamIds, teams]);

    const sellPlayer = () => {
        setIsAuctioning(false);
        const winner = teams.find(t => t.id === highestBidderId);
        if (winner && currentPlayer) {
            setTeams(prev => prev.map(t => {
                if (t.id === winner.id) {
                    return {
                        ...t,
                        purse: Number((t.purse - currentBid).toFixed(2)),
                        squad: [...t.squad, currentPlayer]
                    };
                }
                return t;
            }));
            setBiddingLog(prev => [`SOLD! ${currentPlayer.name} -> ${winner.name} (${currentBid.toFixed(2)} Cr)`, ...prev]);
        }
        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 800);
    };

    const unsoldPlayer = () => {
        setIsAuctioning(false);
        setBiddingLog(prev => [`UNSOLD: ${currentPlayer.name}`, ...prev]);
        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 800);
    };

    useEffect(() => {
        if (!isAuctioning && !auctionFinished) {
            startNextPlayer();
        }
    }, [currentPlayerIdx, sortedPool, isAuctioning, auctionFinished, startNextPlayer]);

    const finishAuction = () => {
        const soldPlayerIds = new Set(teams.flatMap(t => t.squad.map(p => p.id)));
        const unauctioned = gameData.allPlayers.filter(p => !soldPlayerIds.has(p.id));
        // Shuffle the pool slightly so order isn't strictly identical every time
        let pool = shuffle([...unauctioned]);

        const finalTeams = teams.map(team => {
            const isDev = gameData.allTeamsData.find(td => td.id === team.id)?.isDevelopmentTeam;
            let squad = [...team.squad];
            let purse = team.purse;

            const fillNeeded = (role: PlayerRole, count: number, foreignOk: boolean = true) => {
                let existing = squad.filter(p => p.role === role).length;
                while (existing < count && pool.length > 0) {
                    // Randomly pick from the top few available players of that role
                    const candidates = pool.filter(p => p.role === role && (foreignOk || !p.isForeign))
                                           .sort((a,b) => Math.max(b.battingSkill, b.secondarySkill) - Math.max(a.battingSkill, a.secondarySkill))
                                           .slice(0, 3); // Pick from top 3

                    if (candidates.length > 0) {
                        const p = candidates[Math.floor(Math.random() * candidates.length)];
                        const poolIdx = pool.findIndex(pl => pl.id === p.id);
                        pool.splice(poolIdx, 1);
                        squad.push(p);
                        existing++;
                        if (!isDev) purse = Math.max(0, purse - 0.2);
                    } else break;
                }
            };

            fillNeeded(PlayerRole.WICKET_KEEPER, TARGET_KEEPERS);
            fillNeeded(PlayerRole.ALL_ROUNDER, TARGET_ALL_ROUNDERS);
            fillNeeded(PlayerRole.SPIN_BOWLER, TARGET_SPINNERS);
            fillNeeded(PlayerRole.FAST_BOWLER, TARGET_FAST);

            let openersCount = squad.filter(p => p.isOpener && p.role === PlayerRole.BATSMAN).length;
            while (openersCount < TARGET_OPENERS && pool.length > 0) {
                const openerCandidates = pool.filter(p => p.isOpener && p.role === PlayerRole.BATSMAN)
                                            .sort((a,b) => b.battingSkill - a.battingSkill)
                                            .slice(0, 3);
                if (openerCandidates.length > 0) {
                    const p = openerCandidates[Math.floor(Math.random() * openerCandidates.length)];
                    const poolIdx = pool.findIndex(pl => pl.id === p.id);
                    pool.splice(poolIdx, 1);
                    squad.push(p);
                    openersCount++;
                } else break;
            }

            // Final fill to squad size
            while (squad.length < 18 && pool.length > 0) {
                const fillCandidates = pool.sort((a,b) => Math.max(b.battingSkill, b.secondarySkill) - Math.max(a.battingSkill, a.secondarySkill))
                                            .slice(0, 5);
                const p = fillCandidates[Math.floor(Math.random() * fillCandidates.length)];
                const poolIdx = pool.findIndex(pl => pl.id === p.id);
                pool.splice(poolIdx, 1);
                squad.push(p);
                if (!isDev) purse = Math.max(0, purse - 0.2);
            }

            return { ...team, squad, purse };
        });

        onAuctionComplete(finalTeams);
    };

    return (
        <div className="h-full flex flex-col bg-[#020617] text-white font-sans overflow-hidden relative">
            {activeOverlay === 'franchises' && (
                <div className="absolute inset-0 z-50 bg-slate-950 flex flex-col p-4 animate-in slide-in-from-bottom duration-300">
                    <div className="flex justify-between items-center mb-4 border-b border-slate-800 pb-4">
                        <h2 className="text-xl font-black italic tracking-tighter uppercase">FRANCHISE ROSTERS</h2>
                        <button onClick={() => setActiveOverlay('none')} className="bg-slate-800 p-2 rounded-full"><Icons.X /></button>
                    </div>
                    <div className="flex-1 overflow-y-auto space-y-6">
                        {teams.map(team => {
                            const td = gameData.allTeamsData.find(d => d.id === team.id);
                            if (td?.isDevelopmentTeam) return null;
                            return (
                                <div key={team.id} className={`p-4 rounded-2xl border ${team.id === gameData.userTeamId ? 'bg-slate-900 border-teal-500 shadow-lg' : 'bg-slate-900/40 border-slate-800'}`}>
                                    <div className="flex justify-between mb-3 border-b border-white/5 pb-2">
                                        <div>
                                            <h4 className="font-black uppercase tracking-tighter text-sm">{team.name}</h4>
                                            <p className="text-[10px] text-zinc-500">{team.squad.length}/22 signed</p>
                                        </div>
                                        <span className="text-sm font-black text-teal-400">{team.purse.toFixed(2)} Cr</span>
                                    </div>
                                    <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                                        {team.squad.map(p => (
                                            <div key={p.id} className="flex justify-between text-[10px]">
                                                <span className="truncate max-w-[80px]">{p.name}</span>
                                                <span className={`${getRoleColor(p.role)} font-bold`}>{p.role}</span>
                                            </div>
                                        ))}
                                        {team.squad.length === 0 && <p className="text-[10px] text-zinc-600 italic col-span-2">No signings yet...</p>}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            {/* Header */}
            <div className="bg-[#0f172a] p-4 pt-10 border-b border-slate-800 flex flex-col gap-2 shadow-2xl z-10">
                <div className="flex justify-between items-center">
                    <div className="flex items-center gap-2">
                        <div className="bg-yellow-500 text-black px-2 py-0.5 rounded font-black text-xs skew-x-[-12deg]">LIVE DRAFT</div>
                        <h1 className="text-sm font-black text-slate-300 tracking-tight uppercase">Best-to-Worst</h1>
                    </div>
                    <div className="text-right">
                        <span className="text-xl font-black text-teal-400">{userTeam?.purse?.toFixed(2) || '0.00'} Cr</span>
                        <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest leading-none">Your Purse</p>
                    </div>
                </div>
            </div>

            {/* Main Area */}
            <div className="flex-1 overflow-y-auto p-4 flex flex-col">
                {!auctionFinished ? (
                    <>
                        {currentPlayer ? (
                            <div className="bg-slate-900/80 rounded-[2rem] border border-slate-800 shadow-2xl p-6 relative flex flex-col">
                                <div className="flex justify-between items-start mb-6">
                                    <div className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${getRoleColor(currentPlayer.role)} bg-opacity-20 border border-current`}>
                                        {getRoleFullName(currentPlayer.role)} {currentPlayer.isForeign ? '✈️' : ''}
                                    </div>
                                    <div className="text-[10px] text-slate-600 font-bold uppercase">Rank #{currentPlayerIdx + 1}</div>
                                </div>

                                <div className="text-center mb-8">
                                    <h2 className="text-4xl font-black italic uppercase tracking-tighter break-words leading-none mb-4">
                                        {currentPlayer.name}
                                    </h2>
                                    <div className="flex justify-center gap-6">
                                        <div className="text-center">
                                            <div className="text-[10px] text-slate-500 font-bold uppercase">Batting</div>
                                            <div className="text-2xl font-black text-blue-400">{currentPlayer.battingSkill}</div>
                                        </div>
                                        <div className="text-center">
                                            <div className="text-[10px] text-slate-500 font-bold uppercase">Bowling</div>
                                            <div className="text-2xl font-black text-red-400">{currentPlayer.secondarySkill}</div>
                                        </div>
                                        <div className="text-center">
                                            <div className="text-[10px] text-slate-500 font-bold uppercase">Base</div>
                                            <div className="text-2xl font-black text-teal-400">{getBasePrice(currentPlayer).toFixed(2)} Cr</div>
                                        </div>
                                    </div>
                                </div>

                                <div className="bg-black/40 rounded-2xl p-4 mb-8 text-center border border-white/5">
                                    <span className="text-[10px] text-slate-500 uppercase font-black tracking-widest block mb-2">LIVE CURRENT BID</span>
                                    <div className="text-6xl font-black text-yellow-400 tabular-nums tracking-tighter">
                                        {currentBid.toFixed(2)} <span className="text-2xl ml-[-10px]">Cr</span>
                                    </div>
                                    <div className="mt-1 text-xs font-bold text-slate-400 uppercase tracking-widest truncate">
                                        {highestBidderId ? `Leading: ${teams.find(t => t.id === highestBidderId)?.name}` : 'Waiting for Opening Bid'}
                                    </div>
                                </div>

                                <div className="flex flex-col gap-3">
                                    {/* Main Bid Button */}
                                    <button 
                                        onClick={() => handleUserBid(1)}
                                        disabled={!isAuctioning || (highestBidderId === userTeam?.id) || (userTeam?.purse || 0) < (currentBid + 0.1)}
                                        className={`w-full py-5 rounded-2xl font-black text-2xl italic uppercase tracking-tighter shadow-2xl transition-all transform active:scale-95 ${
                                            highestBidderId === userTeam?.id 
                                            ? 'bg-emerald-900/40 border-2 border-emerald-500 text-emerald-400' 
                                            : 'bg-teal-500 hover:bg-teal-400 text-black'
                                        } disabled:opacity-20 disabled:grayscale`}
                                    >
                                        Place Bid ({(currentBid + 0.1).toFixed(2)})
                                    </button>

                                    {/* Speed Bidding Row */}
                                    <div className="grid grid-cols-3 gap-2">
                                        <button 
                                            onClick={() => handleUserBid(2)}
                                            disabled={!isAuctioning || (highestBidderId === userTeam?.id) || (userTeam?.purse || 0) < (currentBid + 0.2)}
                                            className="bg-slate-800 hover:bg-teal-600/40 py-2 rounded-xl text-[11px] font-black uppercase tracking-tight border border-white/10 disabled:opacity-20"
                                        >
                                            +0.2 (2x)
                                        </button>
                                        <button 
                                            onClick={() => handleUserBid(5)}
                                            disabled={!isAuctioning || (highestBidderId === userTeam?.id) || (userTeam?.purse || 0) < (currentBid + 0.5)}
                                            className="bg-slate-800 hover:bg-teal-600/40 py-2 rounded-xl text-[11px] font-black uppercase tracking-tight border border-white/10 disabled:opacity-20"
                                        >
                                            +0.5 (5x)
                                        </button>
                                        <button 
                                            onClick={() => handleUserBid(10)}
                                            disabled={!isAuctioning || (highestBidderId === userTeam?.id) || (userTeam?.purse || 0) < (currentBid + 1.0)}
                                            className="bg-slate-800 hover:bg-teal-600/40 py-2 rounded-xl text-[11px] font-black uppercase tracking-tight border border-white/10 disabled:opacity-20"
                                        >
                                            +1.0 (10x)
                                        </button>
                                    </div>

                                    <div className="grid grid-cols-2 gap-3 mt-1">
                                        <button onClick={skipPlayer} className="bg-slate-900/60 hover:bg-slate-700 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-white/5">Pass / Skip</button>
                                        <button onClick={autoAuctionRemaining} className="bg-red-950/40 hover:bg-red-900/60 border border-red-900/50 py-4 rounded-2xl text-[10px] font-black text-red-300 uppercase tracking-widest">Auto Draft</button>
                                    </div>
                                </div>
                            </div>
                        ) : null}

                        <div className="mt-auto pt-6 flex flex-col gap-4">
                            <button onClick={() => setActiveOverlay('franchises')} className="w-full bg-slate-800 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2">
                                <Icons.Podium /> View Franchise Status
                            </button>

                            <div className="bg-black p-4 rounded-2xl h-28 overflow-y-auto border border-white/5 font-mono text-[10px]">
                                <div className="text-slate-600 mb-2 border-b border-white/10 pb-1 uppercase tracking-widest">Broadcast Log</div>
                                {biddingLog.map((log, i) => (
                                    <div key={i} className={`mb-1 ${i === 0 ? 'text-teal-400 font-bold' : 'text-slate-500'}`}>
                                        {log}
                                    </div>
                                ))}
