export const getCommentary = (runs: number, isOut: boolean, batterName: string, bowlerName: string) => {
    if (isOut) return COMMENTARY_TEMPLATES['W'][Math.floor(Math.random() * COMMENTARY_TEMPLATES['W'].length)];
    const key = runs > 6 ? '6' : runs.toString() as keyof typeof COMMENTARY_TEMPLATES;
    const templates = COMMENTARY_TEMPLATES[key] || COMMENTARY_TEMPLATES['0'];
    return templates[Math.floor(Math.random() * templates.length)];
};

