export const formatOvers = (balls: number) => {
    const overs = Math.floor(balls / 6);
    const remainingBalls = balls % 6;
    return `${overs}.${remainingBalls}`;
}

export const getPlayerById = (id: string, allPlayers: Player[]) => {
    const player = allPlayers.find(p => p.id === id);
    return player || { id: 'unknown', name: 'Unknown', role: PlayerRole.BATSMAN, battingSkill: 30, secondarySkill: 30, stats: {} } as any;
};

// ENFORCED 4 FOREIGN PLAYER XI RULE
export const generateAutoXI = (squad: Player[], format: Format) => {
    const xi: Player[] = [];
    const selectedIds = new Set<string>();

    // STRICTLY 4 Foreigners in Main League XI
    let foreignLimit = 4;
    if (format.includes('Development') || format.includes('Rise')) foreignLimit = 0; // Local focus leagues

    const isDomesticOnly = format.includes('First-Class') || format.includes('One-Day');

    const addPlayer = (p: Player) => {
        if (selectedIds.has(p.id)) return false;
        if (p.isForeign) {
            if (foreignLimit <= 0) return false;
            foreignLimit--;
        }
        xi.push(p);
        selectedIds.add(p.id);
        return true;
    };

    // 1. Keeper
    const keeper = [...squad].sort((a,b) => b.battingSkill - a.battingSkill).find(p => p.role === PlayerRole.WICKET_KEEPER);
    if (keeper) addPlayer(keeper);

    // 2. Openers
    squad.filter(p => p.isOpener).sort((a,b) => b.battingSkill - a.battingSkill).forEach(p => { if (xi.length < 11) addPlayer(p); });

    // 3. Best remaining
    const remaining = [...squad].sort((a,b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill));
    remaining.forEach(p => { if (xi.length < 11) addPlayer(p); });

    // If we didn't hit 11 because of strict foreign rules, fill with local talent
    if (xi.length < 11) {
        squad.filter(p => !p.isForeign && !selectedIds.has(p.id)).forEach(p => { if (xi.length < 11) addPlayer(p); });
    }

    return xi.slice(0, 11);
};

export const aggregateStats = (player: Player, formats: Format[]): PlayerStats => {
    const total = { matches: 0, runs: 0, highestScore: 0, average: 0, strikeRate: 0, ballsFaced: 0, dismissals: 0, hundreds: 0, fifties: 0, thirties: 0, fours: 0, sixes: 0, fastestFifty: 0, fastestHundred: 0, wickets: 0, economy: 0, bestBowling: '-', bestBowlingWickets: 0, bestBowlingRuns: 0, bowlingAverage: 0, ballsBowled: 0, runsConceded: 0, threeWicketHauls: 0, fiveWicketHauls: 0, catches: 0, runOuts: 0, manOfTheMatchAwards: 0 };
    formats.forEach(f => {
        const s = player.stats[f];
        if (s) {
            Object.keys(s).forEach(k => {
                if (typeof (s as any)[k] === 'number') (total as any)[k] += (s as any)[k];
            });
            if (s.highestScore > total.highestScore) total.highestScore = s.highestScore;
        }
    });
    total.average = total.dismissals > 0 ? total.runs / total.dismissals : total.runs;
    total.strikeRate = total.ballsFaced > 0 ? (total.runs / total.ballsFaced) * 100 : 0;
    total.bowlingAverage = total.wickets > 0 ? total.runsConceded / total.wickets : 0; 
    total.economy = total.ballsBowled > 0 ? (total.runsConceded / total.ballsBowled) * 6 : 0;
    return total as PlayerStats;
};

export const generateLeagueSchedule = (teams: Team[], format: Format, doubleRoundRobin: boolean = true): Match[] => {
    const matches: Match[] = [];
    if (teams.length < 2) return [];
    let matchCounter = 1;
    for(let i=0; i<teams.length; i++) {
        for(let j=i+1; j<teams.length; j++) {
            matches.push({ matchNumber: matchCounter++, teamA: teams[i].name, teamAId: teams[i].id, vs: 'vs', teamB: teams[j].name, teamBId: teams[j].id, date: `Day ${matchCounter}`, group: 'Round-Robin' });
            if (doubleRoundRobin) matches.push({ matchNumber: matchCounter++, teamA: teams[j].name, teamAId: teams[j].id, vs: 'vs', teamB: teams[i].name, teamBId: teams[i].id, date: `Day ${matchCounter}`, group: 'Round-Robin' });
        }
    }
    matches.push({ matchNumber: 'SF1', teamA: '1st', vs: 'vs', teamB: '4th', date: 'Playoff', group: 'Semi-Finals' });
    matches.push({ matchNumber: 'SF2', teamA: '2nd', vs: 'vs', teamB: '3rd', date: 'Playoff', group: 'Semi-Finals' });
    matches.push({ matchNumber: 'Final', teamA: 'Winner SF1', vs: 'vs', teamB: 'Winner SF2', date: 'Grand Final', group: 'Final' });
    return matches;
};

