                <button
                    key={item.name}
                    onClick={() => setScreen(item.screen)}
                    className={`flex flex-col items-center justify-center space-y-1 w-1/5 pt-2 ${activeScreen === item.screen ? 'text-teal-500' : 'text-gray-500'}`}
                >
                    <item.icon />
                    <span className="text-[10px] font-bold uppercase">{item.name}</span>
                </button>
            ))}
