export const generateAutoXI = (squad: Player[], format: Format) => {
    const isMainLeague = [Format.T20, Format.ODI, Format.FIRST_CLASS].includes(format);
    const xi: Player[] = [];
    const selectedIds = new Set<string>();

    if (isMainLeague) {
        const foreigns = squad.filter(p => p.isForeign).sort((a, b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill)).slice(0, 4);
        const locals = squad.filter(p => !p.isForeign).sort((a, b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill)).slice(0, 7);
        return [...foreigns, ...locals];
    } else {
        // Dev/Rise leagues: Mostly local focus
        return squad.sort((a, b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill)).slice(0, 11);
    }
};

export const aggregateStats = (player: Player, formats: Format[]): PlayerStats => {
    const total = { matches: 0, runs: 0, highestScore: 0, average: 0, strikeRate: 0, ballsFaced: 0, dismissals: 0, hundreds: 0, fifties: 0, thirties: 0, fours: 0, sixes: 0, fastestFifty: 0, fastestHundred: 0, wickets: 0, economy: 0, bestBowling: '-', bestBowlingWickets: 0, bestBowlingRuns: 0, bowlingAverage: 0, ballsBowled: 0, runsConceded: 0, threeWicketHauls: 0, fiveWicketHauls: 0, catches: 0, runOuts: 0, manOfTheMatchAwards: 0 };
    formats.forEach(f => {
        const s = player.stats[f];
        if (s) {
            Object.keys(s).forEach(k => { if (typeof (s as any)[k] === 'number') (total as any)[k] += (s as any)[k]; });
            if (s.highestScore > total.highestScore) total.highestScore = s.highestScore;
        }
    });
    total.average = total.dismissals > 0 ? total.runs / total.dismissals : total.runs;
    total.strikeRate = total.ballsFaced > 0 ? (total.runs / total.ballsFaced) * 100 : 0;
    total.bowlingAverage = total.wickets > 0 ? total.runsConceded / total.wickets : 0; 
    total.economy = total.ballsBowled > 0 ? (total.runsConceded / total.ballsBowled) * 6 : 0;
    return total as PlayerStats;
};

