export const generateLeagueSchedule = (teams: Team[], format: Format, doubleRoundRobin: boolean = true): Match[] => {
    const matches: Match[] = [];
    if (teams.length < 2) return [];
    let matchCounter = 1;
    for(let i=0; i<teams.length; i++) {
        for(let j=i+1; j<teams.length; j++) {
            matches.push({ matchNumber: matchCounter++, teamA: teams[i].name, vs: 'vs', teamB: teams[j].name, date: `Day ${matchCounter}`, group: 'Round-Robin' });
            if (doubleRoundRobin) matches.push({ matchNumber: matchCounter++, teamA: teams[j].name, vs: 'vs', teamB: teams[i].name, date: `Day ${matchCounter}`, group: 'Round-Robin' });
        }
    }
    matches.push({ matchNumber: 'SF1', teamA: '1st', vs: 'vs', teamB: '4th', date: 'Playoff', group: 'Semi-Finals' });
    matches.push({ matchNumber: 'SF2', teamA: '2nd', vs: 'vs', teamB: '3rd', date: 'Playoff', group: 'Semi-Finals' });
    matches.push({ matchNumber: 'Final', teamA: 'Winner SF1', vs: 'vs', teamB: 'Winner SF2', date: 'Final', group: 'Final' });
    return matches;
};

