import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Player, Team, GameData, PlayerRole } from '../types';
import { getRoleColor, getRoleFullName } from '../utils';
import { Icons } from './Icons';
import { SQUAD_LOCAL_LIMIT, SQUAD_FOREIGN_LIMIT } from '../data';

interface AuctionRoomProps {
    gameData: GameData;
    onAuctionComplete: (updatedTeams: Team[]) => void;
}

const STARTING_PURSE = 50.0;

const AuctionRoom: React.FC<AuctionRoomProps> = ({ gameData, onAuctionComplete }) => {
    const [teams, setTeams] = useState<Team[]>(() => 
        gameData.teams.map(t => ({ ...t, squad: t.squad || [], purse: t.purse || STARTING_PURSE }))
    );

    const [currentPlayerIdx, setCurrentPlayerIdx] = useState(0);
    const [currentBid, setCurrentBid] = useState(0);
    const [highestBidderId, setHighestBidderId] = useState<string | null>(null);
    const [isAuctioning, setIsAuctioning] = useState(false);
    const [biddingLog, setBiddingLog] = useState<string[]>([]);
    const [auctionFinished, setAuctionFinished] = useState(false);

    /**
     * ENFORCED AUCTION RULE:
     * - Top Countries: 10 players finalized
     * - Small Teams: 2 players finalized
     */
    const finalAuctionPool = useMemo(() => {
        const countries = Array.from(new Set(gameData.allPlayers.map(p => p.nationality)));
        const pool: Player[] = [];

        countries.forEach(country => {
            const players = gameData.allPlayers.filter(p => p.nationality === country);
            if (country === 'Pakistan') {
                pool.push(...players); // All locals available
            } else {
                const tier = players[0]?.countryTier;
                const limit = tier === 'top' ? 10 : 2;
                pool.push(...players.sort((a,b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill)).slice(0, limit));
            }
        });
        return pool.sort((a,b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill));
    }, [gameData.allPlayers]);

    const currentPlayer = finalAuctionPool[currentPlayerIdx] || null;
    const userTeam = teams.find(t => t.id === gameData.userTeamId);

    const startNextPlayer = useCallback(() => {
        if (auctionFinished) return;
        if (currentPlayerIdx >= finalAuctionPool.length) { setAuctionFinished(true); return; }
        const p = finalAuctionPool[currentPlayerIdx];
        setCurrentBid(p.battingSkill > 80 ? 2.0 : 0.5);
        setHighestBidderId(null);
        setIsAuctioning(true);
        setBiddingLog(prev => [`Lot #${currentPlayerIdx + 1}: ${p.name} (${p.nationality})`, ...prev.slice(0, 5)]);
    }, [currentPlayerIdx, finalAuctionPool, auctionFinished]);

    const handleUserBid = () => {
        if (!userTeam || !isAuctioning || !currentPlayer) return;

        const isForeign = currentPlayer.nationality !== 'Pakistan';
        const foreignCount = userTeam.squad.filter(p => p.isForeign).length;
        const localCount = userTeam.squad.filter(p => !p.isForeign).length;

        if (isForeign && foreignCount >= SQUAD_FOREIGN_LIMIT) {
            setBiddingLog(prev => [`Limit: Max 8 Foreigners!`, ...prev]);
            return;
        }
        if (!isForeign && localCount >= SQUAD_LOCAL_LIMIT) {
            setBiddingLog(prev => [`Limit: Exactly 12 Locals!`, ...prev]);
            return;
        }

        const nextBid = Number((currentBid + 0.1).toFixed(2));
        if (userTeam.purse < nextBid) return;

        setCurrentBid(nextBid);
        setHighestBidderId(userTeam.id);
    };

    useEffect(() => {
        if (!isAuctioning || !currentPlayer || auctionFinished) return;
        const timer = setTimeout(() => {
            const bidder = teams.find(t => {
                const isFor = currentPlayer.isForeign;
                const count = t.squad.filter(p => p.isForeign === isFor).length;
                const limit = isFor ? SQUAD_FOREIGN_LIMIT : SQUAD_LOCAL_LIMIT;
                return t.id !== highestBidderId && t.purse >= currentBid + 0.1 && count < limit;
            });
            if (bidder && Math.random() > 0.5) {
                setCurrentBid(prev => Number((prev + 0.1).toFixed(2)));
                setHighestBidderId(bidder.id);
            } else if (highestBidderId) {
                sellPlayer();
            }
        }, 1000);
        return () => clearTimeout(timer);
    }, [isAuctioning, currentBid, highestBidderId, currentPlayer, teams]);

    const sellPlayer = () => {
        setIsAuctioning(false);
        const winner = teams.find(t => t.id === highestBidderId);
        if (winner && currentPlayer) {
            setTeams(prev => prev.map(t => t.id === winner.id ? { ...t, purse: Number((t.purse - currentBid).toFixed(2)), squad: [...t.squad, currentPlayer] } : t));
            setBiddingLog(prev => [`SOLD! ${currentPlayer.name} to ${winner.name}`, ...prev]);
        }
        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 600);
    };

    useEffect(() => { if (!isAuctioning && !auctionFinished) startNextPlayer(); }, [currentPlayerIdx, isAuctioning, auctionFinished, startNextPlayer]);

    return (
        <div className="h-full flex flex-col bg-slate-950 text-white p-4">
            <div className="flex justify-between mb-4 border-b border-slate-800 pb-2">
                <h2 className="font-black italic uppercase">PSL 2026 DRAFT</h2>
                <div className="text-teal-400 font-bold">{userTeam?.purse.toFixed(2)} Cr</div>
            </div>
            {!auctionFinished && currentPlayer ? (
                <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 flex flex-col gap-4">
                    <div className="text-center">
                        <div className={`text-[10px] uppercase font-bold px-2 py-1 rounded inline-block ${currentPlayer.isForeign ? 'bg-purple-900' : 'bg-green-900'}`}>
                            {currentPlayer.nationality}
                        </div>
                        <h3 className="text-4xl font-black italic mt-2 uppercase">{currentPlayer.name}</h3>
                        <p className="text-slate-500 font-bold">{getRoleFullName(currentPlayer.role)}</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4 text-center bg-black/40 p-4 rounded-2xl">
                         <div><div className="text-[10px] text-slate-500 font-bold uppercase">Batting</div><div className="text-2xl font-black">{currentPlayer.battingSkill}</div></div>
                         <div><div className="text-[10px] text-slate-500 font-bold uppercase">Bowling</div><div className="text-2xl font-black">{currentPlayer.secondarySkill}</div></div>
                    </div>
                    <div className="text-center py-4">
                        <div className="text-5xl font-black text-yellow-400">{currentBid.toFixed(2)} <span className="text-xl">Cr</span></div>
                        <div className="text-xs text-slate-400 mt-2">Leader: {teams.find(t => t.id === highestBidderId)?.name || 'None'}</div>
                    </div>
                    <button onClick={handleUserBid} disabled={!isAuctioning || highestBidderId === userTeam?.id} className="bg-teal-500 hover:bg-teal-400 py-4 rounded-2xl font-black text-xl uppercase italic disabled:opacity-30">Place Bid</button>
                    <button onClick={() => setAuctionFinished(true)} className="text-xs text-slate-600 font-bold uppercase">Skip to Results</button>
                </div>
            ) : (
                <div className="flex-1 flex flex-col items-center justify-center gap-6">
                    <h2 className="text-3xl font-black uppercase italic">Draft Completed</h2>
                    <button onClick={() => onAuctionComplete(teams)} className="bg-teal-500 px-12 py-4 rounded-full font-black uppercase italic">Enter Career</button>
                </div>
            )}
        </div>
    );
};

