const CareerHub: React.FC<CareerHubProps> = ({ gameData, setGameData, onResetGame, theme, setTheme, saveGame, loadGame, showFeedback }) => {
    const [screen, setScreen] = useState<CareerScreen>('DASHBOARD');
    const [selectedPlayer, setSelectedPlayer] = useState<Player | null>(null);
    const [playerProfileFormat, setPlayerProfileFormat] = useState<Format>(gameData.currentFormat);
    const [selectedMatchResult, setSelectedMatchResult] = useState<MatchResult | null>(null);
    const [forwardSimResults, setForwardSimResults] = useState<MatchResult[]>([]);

    const { runSimulationForCurrentFormat, updateStatsFromMatch } = useSimulation(gameData, setGameData);

    const userTeam = useMemo(() => gameData.teams.find(t => t.id === gameData.userTeamId) || gameData.teams[0], [gameData]);

    const handleEndOfSeason = (retained: Player[]) => {
        setGameData(prev => {
            if (!prev) return null;

            // PROMOTE GOOD PERFORMERS TO NEXT SEASON AUCTION
            // Condition: 45+ Avg or 20+ Wickets in any Dev/Rise format
            const allPlayers = prev.allPlayers.map(p => {
                const totalRuns = Object.values(p.stats).reduce((acc, s) => acc + s.runs, 0);
                const totalOuts = Object.values(p.stats).reduce((acc, s) => acc + s.dismissals, 0);
                const totalWkts = Object.values(p.stats).reduce((acc, s) => acc + s.wickets, 0);
                const avg = totalOuts > 0 ? totalRuns / totalOuts : totalRuns;

                if (avg >= 45 || totalWkts >= 20) {
                    return { ...p, isTopPerformer: true };
                }
                return p;
            });

            return {
                ...prev,
                allPlayers,
                currentSeason: prev.currentSeason + 1,
                currentFormat: Format.T20,
                currentMatchIndex: Object.values(Format).reduce((acc, f) => ({ ...acc, [f]: 0 }), {} as any),
                matchResults: Object.values(Format).reduce((acc, f) => ({ ...acc, [f]: [] }), {} as any),
            };
        });
        setScreen('AUCTION_ROOM');
    };

    const renderScreen = () => {
        const commonProps = { gameData, userTeam, setGameData, setScreen, showFeedback };
        switch(screen) {
            case 'DASHBOARD': return <Dashboard {...commonProps} handlePlayMatch={() => setScreen('LIVE_MATCH')} handleForwardDay={() => {}} />;
            case 'STATS': return <Stats gameData={gameData} viewPlayerProfile={(p,f)=>{ setSelectedPlayer(p); setPlayerProfileFormat(f); setScreen('PLAYER_PROFILE'); }} />;
            case 'AUCTION_ROOM': return <AuctionRoom gameData={gameData} onAuctionComplete={(teams) => { setGameData(p => p?{...p, teams}:null); setScreen('DASHBOARD'); }} />;
            case 'END_OF_FORMAT': return <EndOfFormatScreen gameData={gameData} handleFormatChange={(f) => setGameData(p => p?{...p, currentFormat: f}:null)} handleEndSeason={handleEndOfSeason} />;
            case 'PLAYER_PROFILE': return <PlayerProfile player={selectedPlayer} onBack={() => setScreen('STATS')} initialFormat={playerProfileFormat} />;
            case 'LEAGUES': return <Standings gameData={gameData} />;
            case 'LINEUPS': return <Lineups {...commonProps} handleUpdatePlayingXI={()=>{}} handleUpdateCaptain={()=>{}} />;
            case 'SETTINGS': return <Settings onResetGame={onResetGame} theme={theme} setTheme={setTheme} saveGame={saveGame} loadGame={loadGame} />;
            case 'LIVE_MATCH': {
                const match = gameData.schedule[gameData.currentFormat][gameData.currentMatchIndex[gameData.currentFormat]];
                return <LiveMatchScreen match={match} gameData={gameData} onMatchComplete={(res) => {
                    const updated = updateStatsFromMatch(res, gameData.currentFormat, gameData);
                    updated.currentMatchIndex[gameData.currentFormat]++;
                    setGameData(updated);
                    setSelectedMatchResult(res);
                    setScreen('MATCH_RESULT');
                }} onExit={() => setScreen('DASHBOARD')} />;
            }
            default: return <div className="p-10">Module Ready. Select from Menu.</div>;
        }
    }

    return (
        <div className="flex flex-col h-full bg-white dark:bg-[#2C3531]">
            <main className="flex-grow overflow-y-auto">{renderScreen()}</main>
            <BottomNavBar activeScreen={screen} setScreen={setScreen} />
        </div>
    );
};

